214	Command* CommandManager::FindCommand(const char* cmd) {
215	    Command* result = nullptr;
216	    auto callback = [cmd, &result](Command* command) -> bool {
217	        if (command->get() == cmd || command->shortcut() == cmd) {
218	            result = command;
219	            return true;
220	        }
221	        return false;
222	    };
223	    ForeachCommand(callback);
224	    return result;
225	}
