288	void Android::ForeachInstanceField(art::mirror::Class& clazz, std::function<bool (art::ArtField& field)> fn) {
289	    if (LIKELY(Sdk() >= W)) {
290	        uint32_t size = clazz.NumFields();
291	        if (!size) return;
292	        art::ArtField field(clazz.GetFields(), clazz);
293	        int i = 0;
294	        do {
295	            if (!field.IsStatic())
296	                if (fn(field)) break;
297	            field.MovePtr(SIZEOF(ArtField));
298	            i++;
299	        } while(i < size);
300	    } else {
301	        uint32_t size = clazz.NumInstanceFields();
302	        if (!size) return;
303	        art::ArtField field(clazz.GetIFields(), clazz);
304	        int i = 0;
305	        do {
306	            if (fn(field)) break;
307	            field.MovePtr(SIZEOF(ArtField));
308	            i++;
309	        } while(i < size);
310	    }
311	}
