361	    auto visit_methods_fn = [&](uint64_t methods, uint32_t size, uint32_t off) {
362	        if ((size - off) > 0) {
363	            api::MemoryRef base(methods, clazz);
364	            base.Prepare(false);
365	            int i = off;
366	            do {
367	                art::ArtMethod method(base.Ptr() + i * SIZEOF(ArtMethod), base);
368	                if (fn(method)) break;
369	                i++;
370	            } while(i < size);
371	        }
372	    };
