384	void Android::ForeachObjects(std::function<bool (art::mirror::Object& object)> fn, int flag, bool check) {
385	    art::Runtime& runtime = art::Runtime::Current();
386	    art::gc::Heap& heap = runtime.GetHeap();
387	
388	    auto walkfn = [&](art::gc::space::Space* space) {
389	        LOGD("Walk [%s] ...\n", space->GetName());
390	        try {
391	            if (space->IsVaildSpace()) {
392	                space->Walk(fn, check);
393	            } else {
394	                LOGE("%s invalid space.\n", space->GetName());
395	            }
396	        } catch (InvalidAddressException& e) {
397	            LOGW("Walk [%s] was interrupted!\n", space->GetName());
398	        }
399	    };
400	
401	    for (const auto& space : heap.GetContinuousSpaces()) {
402	        if (space->IsImageSpace()) {
403	            if (flag & EACH_IMAGE_OBJECTS) walkfn(space.get());
404	        } else if (space->IsZygoteSpace()) {
405	            if (flag & EACH_ZYGOTE_OBJECTS) walkfn(space.get());
406	        } else if (space->IsRegionSpace() || space->IsBumpPointerSpace()) {
407	            if (flag & EACH_APP_OBJECTS) walkfn(space.get());
408	        } else if (space->IsMallocSpace()) {
409	            if (space->IsRosAllocSpace()) {
410	                if (flag & EACH_APP_OBJECTS) walkfn(space.get());
411	            } else if (space->IsDlMallocSpace()) {
412	                if (flag & EACH_APP_OBJECTS) walkfn(space.get());
413	            }
414	        } else if (space->IsFakeSpace()) {
415	            if (flag & EACH_FAKE_OBJECTS) walkfn(space.get());
416	        } else {
417	            if (space->GetType() != art::gc::space::kSpaceTypeInvalidSpace) {
418	                walkfn(space.get());
419	            } else {
420	                LOGE("please run sysroot libart.so and run env art -c, %s invalid space.\n", space->GetName());
421	            }
422	        }
423	    }
424	
425	    for (const auto& space : heap.GetDiscontinuousSpaces()) {
426	        if (flag & EACH_APP_OBJECTS) walkfn(space.get());
427	    }
428	}
