434	
435	Runtime& Runtime::Current() {
436	    Runtime& runtime = Android::GetRuntime();
437	    if (!Android::IsSdkReady()) {
438	        LOGE("Please command \"env config --sdk <SDK>!!\"\n");
439	        if (runtime.Ptr()) {
440	            runtime.CleanCache();
441	            runtime = 0x0;
442	        }
443	        return runtime;
444	    }
445	
446	    if (!runtime.Ptr()) {
447	        api::MemoryRef value = 0x0;
448	        try {
449	            value = Android::DlSym(Android::ART_RUNTIME_INSTANCE);
450	            runtime_instance_ori_cache = value.valueOf();
451	            if (!runtime_instance_ori_cache.IsValid())
452	                throw InvalidAddressException(runtime_instance_ori_cache.Ptr());
453	            runtime = runtime_instance_ori_cache;
454	
455	#if defined(__ART_RUNTIME_PARSER__)
456	            // double check runtime callee_method
457	            uint64_t callee_methods[6] = {0x0};
458	            memset(callee_methods, 0x0, sizeof(callee_methods));
459	            uint32_t sizeof_callee_methods = SizeOfCalleeMethods();
460	            AnalysisCalleeSaveMethods(callee_methods, sizeof_callee_methods);
461	
462	            //maybe invalid
463	            if (!callee_methods[0])
464	                return runtime;
465	
466	            if (memcmp(reinterpret_cast<void *>(callee_methods),
467	                        reinterpret_cast<void *>(runtime.Real()),
468	                        sizeof_callee_methods)) {
469	                LOGW("'%s' = 0x%" PRIx64 ", but callee_save_methods_ not match image.\n",
470	                        Android::ART_RUNTIME_INSTANCE, runtime.Ptr());
471	                runtime = AnalysisRuntime(callee_methods, sizeof_callee_methods);
472	            }
473	#endif
474	        } catch(InvalidAddressException& e) {
475	            runtime = AnalysisInstance();
476	        }
477	
478	#if defined(__ART_RUNTIME_MAIN_PROP_PARSER__)
479	        if (Android::Sdk() >= Android::V && runtime.Ptr()) {
480	            uint64_t point_size = CoreApi::GetPointSize();
481	            int32_t counter = -1;
482	            LoadBlock* block = nullptr;
483	            do {
484	                counter++;
485	                uint32_t offset = OFFSET(Runtime, heap_) + (counter * point_size);
486	                uint32_t finalizer_timeout_ms_ = runtime.value32Of(offset - point_size);
487	                // maybe filter finalizer_timeout_ms_
488	                if ((runtime.valueOf(offset) & 0xFFFFFFFFFFF00000ULL)
489	                        && finalizer_timeout_ms_ >= 10000 && finalizer_timeout_ms_ < 1048576)
490	                    block = CoreApi::FindLoadBlock(runtime.valueOf(offset) , false);
491	            } while (!block && counter < 100);
492	
493	            if (counter && counter < 100 && block) {
494	                uint32_t cloc_off = counter * point_size;
495	                __Runtime_offset__.heap_ += cloc_off;
496	                __Runtime_offset__.monitor_pool_ += cloc_off;
497	                __Runtime_offset__.thread_list_ += cloc_off;
498	                __Runtime_offset__.class_linker_ += cloc_off;
499	                __Runtime_offset__.java_vm_ += cloc_off;
500	                __Runtime_offset__.jit_ += cloc_off;
501	            }
502	        }
503	#endif // __ART_RUNTIME_MAIN_PROP_PARSER__
504	    }
505	    return runtime;
506	}
507	
508	void Runtime::AnalysisCalleeSaveMethods(uint64_t *callee_methods, uint32_t sizeof_callee_methods) {
509	    if (!callee_methods)
510	        return;
511	
512	    auto callback = [&](LoadBlock *block) -> bool {
513	        if (memcmp(reinterpret_cast<void *>(block->begin()),
514	                   reinterpret_cast<void *>(ImageHeader::kMagic),
515	                   sizeof(ImageHeader::kMagic)))
516	            return false;
517	
518	        ImageHeader header(block->vaddr(), block);
519	        void *image_callee_methods = reinterpret_cast<void *>(header.image_methods()
520	                + ImageHeader::ImageMethod::kSaveAllCalleeSavesMethod * sizeof(uint64_t));
521	
522	        if (!reinterpret_cast<uint64_t *>(image_callee_methods)[0])
523	            return false;
524	
525	        memcpy(callee_methods, image_callee_methods, sizeof_callee_methods);
526	        return true;
527	    };
528	    CoreApi::ForeachLoadBlock(callback, true, true);
529	}
530	
531	Runtime Runtime::AnalysisRuntime(uint64_t *callee_methods, uint32_t sizeof_callee_methods) {
532	    Runtime runtime = 0x0;
533	    uint64_t point_size = CoreApi::GetPointSize();
534	    auto match = [&](LoadBlock *block) -> bool {
535	        // must can write vma
536	        if (!(block->flags() & Block::FLAG_W))
537	            return false;
538	
539	        if (!memcmp(reinterpret_cast<void *>(block->begin()),
540	                   reinterpret_cast<void *>(ImageHeader::kMagic),
541	                   sizeof(ImageHeader::kMagic)))
542	            return false;
543	
544	        uint64_t current = block->begin();
545	        uint64_t outsize = block->begin() + block->size();
546	        while (current + sizeof_callee_methods < outsize) {
547	            if (!memcmp(reinterpret_cast<void *>(callee_methods),
548	                        reinterpret_cast<void *>(current),
549	                        sizeof_callee_methods)) {
550	                runtime = current - block->begin() + block->vaddr();
551	                runtime.checkCopyBlock(block);
552	                ArtMethod& resolution_method_ = runtime.GetResolutionMethod();
553	                if (resolution_method_.Block() &&
554	                        resolution_method_.Block()->virtualContains(callee_methods[0])) {
555	                    LOGD(">>> '%s' = 0x%" PRIx64 "\n", Android::ART_RUNTIME_INSTANCE, runtime.Ptr());
556	                    return true;
557	                }
558	            }
559	            current += point_size;
560	        }
561	        return false;
562	    };
563	    CoreApi::ForeachLoadBlock(match, true, true);
564	    return runtime;
565	}
