567	Runtime Runtime::AnalysisInstance() {
568	    uint64_t callee_methods[6] = {0x0};
569	    memset(callee_methods, 0x0, sizeof(callee_methods));
570	    uint32_t sizeof_callee_methods = SizeOfCalleeMethods();
571	    AnalysisCalleeSaveMethods(callee_methods, sizeof_callee_methods);
572	
573	    //maybe invalid
574	    if (!callee_methods[0])
575	        return 0x0;
576	
577	    return AnalysisRuntime(callee_methods, sizeof_callee_methods);
578	}
