662	ArtMethod& Runtime::GetCalleeSaveMethodUnchecked(CalleeSaveType type) {
663	    uint32_t index = static_cast<uint32_t>(type);
664	    if (!callee_save_methods_cache[index].Ptr()) {
665	        memset(callee_save_methods_cache, 0x0, sizeof(callee_save_methods_cache));
666	        api::MemoryRef ref = callee_save_methods();
667	        for (uint32_t i = 0; i < kNumCalleeMethodsCount; ++i) {
668	            callee_save_methods_cache[i] = ref.value64Of(i * sizeof(uint64_t));
669	            callee_save_methods_cache[i].Prepare(false);
670	        }
671	    }
672	    return callee_save_methods_cache[index];
673	}
