404	void CoreApi::SysRoot(const char* path) {
405	    std::vector<char *> dirs;
406	    std::unique_ptr<char[], void(*)(void*)> newpath(strdup(path), free);
407	    char *token = strtok(newpath.get(), ":");
408	    while (token != nullptr) {
409	        dirs.push_back(token);
410	        token = strtok(nullptr, ":");
411	    }
412	
413	    auto callback = [dirs](LinkMap* map) -> bool {
414	        std::unique_ptr<char[], void(*)(void*)> newname(strdup(map->name()), free);
415	        char *ori_file = strtok(newname.get(), "!");
416	        char *sub_file = strtok(NULL, "!");
417	
418	        std::string filepath;
419	        for (char *dir : dirs) {
420	            if (Utils::SearchFile(dir, &filepath, ori_file))
421	                break;
422	        }
423	        if (filepath.length() > 0) {
424	            if (INSTANCE->sysroot(map, filepath.c_str(), sub_file)) {
425	                map->ReadSymbols();
426	                if (SYSROOT_CALLBACK)
427	                    SYSROOT_CALLBACK(map);
428	            }
429	        }
430	        return false;
431	    };
432	    INSTANCE->foreachLinkMap(callback);
433	}
