442	bool CoreApi::Read(uint64_t vaddr, uint64_t size, uint8_t* buf, int opt) {
443	    LoadBlock* block = FindLoadBlock(vaddr);
444	
445	    uint64_t raddr = GetReal(vaddr, opt);
446	    if (!raddr)
447	        return false;
448	
449	    if ((vaddr + size) > (block->vaddr() + block->size())) {
450	        uint64_t newsize = (block->vaddr() + block->size() - vaddr);
451	        memcpy(buf, reinterpret_cast<void *>(raddr), newsize);
452	    } else {
453	        memcpy(buf, reinterpret_cast<void *>(raddr), size);
454	    }
455	    return true;
456	}
