489	uint64_t CoreApi::v2r(uint64_t vaddr, int opt) {
490	    LoadBlock* block = findLoadBlock(vaddr, true);
491	    if (block && block->isValid()) {
492	        uint64_t raddr = block->begin(opt);
493	        if (raddr) {
494	            return raddr + ((vaddr & block->VabitsMask()) - block->vaddr());
495	        } else {
496	            return 0x0;
497	        }
498	    }
499	    throw InvalidAddressException(vaddr);
500	}
